8368	\begin{lemma}[The category of schemes is finitary extensive]
8369	  \label{lem:finitaryExtensive_scheme_mathlib}
8370	  \lean{AlgebraicGeometry.instFinitaryExtensiveScheme}
8371	  \mathlibok
8372	  \textit{Provided by Mathlib.}
8373	  The category \(\operatorname{Scheme}\) is finitary extensive: finite coproducts are disjoint
8374	  and universal (stable under pullback). In particular it is finitary pre-extensive and has
8375	  finite coproducts and pullbacks, so the abstract distributivity of
8376	  Lemma~\ref{lem:isIso_sigmaDesc_map_mathlib} applies at \(\mathcal{C} = \operatorname{Scheme}\).
8377	\end{lemma}
8378	
8379	\begin{lemma}[Coproducts distribute over the binary fibre product]
8380	  \label{lem:isIso_sigmaDesc_map_mathlib}
8381	  \lean{CategoryTheory.FinitaryPreExtensive.isIso_sigmaDesc_map}
8382	  \mathlibok
8383	  \textit{Provided by Mathlib.}
8384	  In a finitary pre-extensive category with pullbacks, for finite index types \(\iota, \iota'\),
8385	  a base \(S\), and families \((X_i \to S)_i\), \((Y_j \to S)_j\), the canonical map
8386	  \(\coprod_{(i,j)} (X_i \times_S Y_j) \to (\coprod_i X_i) \times_S (\coprod_j Y_j)\),
8387	  \(\operatorname{Sigma.desc}\) of the pullback maps, is an isomorphism. Taking one family to be a
8388	  singleton gives the one-sided distributivity
8389	  \((\coprod_i X_i) \times_S Y \cong \coprod_i (X_i \times_S Y)\) used in the induction of
8390	  Lemma~\ref{lem:coproduct_distrib_fibrePower}.
8391	\end{lemma}
