8409	\begin{lemma}[Pullback of two open immersions is the intersection open]
8410	  \label{lem:isPullback_opens_inf_mathlib}
8411	  \lean{AlgebraicGeometry.isPullback_opens_inf}
8412	  \mathlibok
8413	  \textit{Provided by Mathlib.}
8414	  For two opens \(U, V\) of a scheme \(X\), the square with vertex \((U \sqcap V).\mathrm{toScheme}\)
8415	  and the two \(\operatorname{homOfLE}\) inclusions into \(U\) and \(V\) is a pullback of the open
8416	  immersions \(U.\iota, V.\iota\). Equivalently \(\operatorname{pullback} U.\iota\,V.\iota \cong
8417	  (U \sqcap V).\mathrm{toScheme}\): the fibre product of open immersions over \(X\) is the
8418	  intersection of their images.
8419	\end{lemma}
