8433	\begin{lemma}[The identity arrow is terminal in the slice category]
8434	  \label{lem:over_mkIdTerminal_mathlib}
8435	  \lean{CategoryTheory.Over.mkIdTerminal}
8436	  \mathlibok
8437	  \textit{Provided by Mathlib.}
8438	  For an object \(S\) of a category, \(\operatorname{Over.mk}(\mathrm{id}_S)\) is a terminal object
8439	  of the slice category \(\operatorname{Over} S\). This is what makes the base of a wide pullback
8440	  over \(S\) terminal in the slice, so that
8441	  Lemma~\ref{lem:widePullbackCone_isLimitOfFan_mathlib} exhibits the fibre power over \(S\) as the
8442	  product in \(\operatorname{Over} S\) in Lemma~\ref{lem:widePullback_overX_eq_prod}.
8443	\end{lemma}
