8445	\begin{lemma}[Nested coproducts flatten to a coproduct over pairs]
8446	  \label{lem:sigmaSigmaIso_mathlib}
8447	  \lean{CategoryTheory.Limits.sigmaSigmaIso}
8448	  \mathlibok
8449	  \textit{Provided by Mathlib.}
8450	  For a doubly-indexed family \((Z_{i,j})\), the nested coproduct is the coproduct over pairs:
8451	  \(\coprod_i \coprod_j Z_{i,j} \cong \coprod_{(i,j)} Z_{i,j}\). This collapses the nested
8452	  coproduct produced by one inductive step of the binary distributivity into a single coproduct
8453	  over the multi-indices \(\sigma\) in Lemma~\ref{lem:coproduct_distrib_fibrePower}.
8454	\end{lemma}
